5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	function computePremiumBreakdown(items: any[]): { itemPremiums: number; policyBase: number } {
17	  const componentCounts: Record<string, number> = {};
18	  let itemPremiums = 0;
19	  let policyBase = 0;
20	
21	  for (const item of items) {
22	    if (COMPONENT_TYPES.has(item.type)) {
23	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
24	    } else {
25	      const basePremium = BASE_PREMIUM[item.type] ?? 0;
26	      policyBase += basePremium;
27	      const cursedSurcharge = item.cursed ? basePremium * 0.5 : 0;
28	      const enchantmentSurcharge = item.enchantment >= 5 ? basePremium * 0.3 : 0;
29	      itemPremiums += basePremium + cursedSurcharge + enchantmentSurcharge;
30	    }
31	  }
32	
33	  for (const [type, count] of Object.entries(componentCounts)) {
34	    const unitPrice = BASE_PREMIUM[type] ?? 0;
35	    const componentPremium = count === BLOCK_SIZE ? BLOCK_PREMIUM : count * unitPrice;
36	    itemPremiums += componentPremium;
37	    policyBase += count * unitPrice;
38	  }
39	
40	  return { itemPremiums, policyBase };
41	}
42	
43	export function processScenario(scenario: any): unknown {
44	  const results = scenario.steps.map((step: any, index: number) => {
45	    const { itemPremiums, policyBase } = computePremiumBreakdown(step.items);
46	    const firstInsuranceSurcharge = policyBase * 0.1;
47	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
48	    const followUpDiscount = index > 0 ? policyBase * 0.15 : 0;
49	    const premium = Math.ceil(itemPremiums + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
50	    return { premium };
51	  });
52	  return { results };
53	}
